11	-- ramp cmd and according to the incmrenet that is fed at its input will rise 
12	-- within the "time specified" to its target level. The output will stay high
13	-- until a new ramp cmd occurs (pulse) and then it will go low accordingly. 
14	-- increment should be fed at the input.
15	-- A small state machine allows knowing in which state the pulse is see below:
16	--          
17	--  init   ____________     flat     init
18	--        /|          |\           |
19	--       / |          | \          |
20	-- _____/  |          |  \_________| 
21	--   00 |01|    11    |10| 11      | 00
22	
23	library ieee;
24	use ieee.std_logic_1164.all;
25	use ieee.numeric_std.all;
26	
27	-- @formatter:off
28	entity psi_common_ramp_gene is
29	  generic(width_g    : natural   := 16;                            -- accumulator width
30	          is_sign_g  : boolean   := false;                         -- sign / unsign
31	          rst_pol_g  : std_logic := '1';                           -- polarity reset	
32	          init_val_g : integer  := 50);                            -- init output value at start-up
33	  port(clk_i         : in  std_logic;                              -- system clock
34	       rst_i         : in  std_logic;                              -- sync reset
35	       vld_i         : in  std_logic;                              -- strobe input
36	       tgt_lvl_i     : in  std_logic_vector(width_g - 1 downto 0); -- Target pulse level
37	       ramp_inc_i    : in  std_logic_vector(width_g - 1 downto 0); -- steepness of the ramp (positive, also for ramping down)
38	       ramp_cmd_i    : in  std_logic;                              -- start ramping
39	       init_cmd_i    : in  std_logic;                              -- go to init whatever state
40	       sts_o         : out std_logic_vector(1 downto 0);           -- FSM status
41	       vld_o         : out std_logic;                              -- Pulse strobe output
42	       puls_o        : out std_logic_vector(width_g - 1 downto 0));-- Pulse value
43	end entity;
44	-- @formatter:on
45	
46	architecture rtl of psi_common_ramp_gene is
47	  --*** internal declaration ***
48	  type fsm_t is (zero, up, flat, dw);
49	  attribute enum_encoding : string;
50	  attribute enum_encoding of fsm_t : type is "00 01 11 10";
51	  -- record
52	  type two_process_t is record
53	    fsm_state : fsm_t;
54	    status    : std_logic_vector(1 downto 0);
55	    pulse     : unsigned(width_g downto 0);
56	    spulse    : signed(width_g downto 0);
57	    str_s     : std_logic;
58	  end record;
59	  --signals
60	  signal r, rin           : two_process_t;
61	
62	begin
63	
64	  proc_comb : process(r, ramp_inc_i, ramp_cmd_i, init_cmd_i, vld_i, tgt_lvl_i)
65	    variable v : two_process_t;
66	  begin
67	    v := r;
68	
69	    case r.fsm_state is
70	
71	      when zero =>
72	        v.status := "00";
73	        -- *** pulse set to 0 ***
74	        v.pulse  := to_unsigned(init_val_g, width_g + 1); 
75	        v.spulse := to_signed(init_val_g, width_g +1);    
76	        -- *** decision maker ::  states change ***
77	        if ramp_cmd_i = '1' and init_cmd_i = '0' then
78	          v.fsm_state := up;
79	        end if;
80	
81	      when up =>
82	        v.status := "01";
83	        -- *** increase pulse :: accu ***
84	        if vld_i = '1' then
85	          if not is_sign_g then
86	            v.pulse := r.pulse + resize(unsigned(ramp_inc_i), width_g + 1);
87	            if r.pulse(width_g downto 0) >= resize(unsigned(tgt_lvl_i) - unsigned(ramp_inc_i), width_g + 1) or
88	               (unsigned(tgt_lvl_i) <= unsigned(ramp_inc_i)) then
89	              v.fsm_state := flat;
90	              v.pulse     := resize(unsigned(tgt_lvl_i), width_g + 1);
91	            end if;
92	          else
93	            -- *** signed ***
94	             v.spulse := r.spulse + resize(signed(ramp_inc_i), width_g + 1);
95	            if r.spulse(width_g downto 0) >= resize(signed(tgt_lvl_i) - signed(ramp_inc_i), width_g + 1) or
96	               (signed(tgt_lvl_i) <= signed(ramp_inc_i)) then
97	              v.fsm_state := flat;
98	              v.spulse     := resize(signed(tgt_lvl_i), width_g + 1);
99	            end if;
100	          end if;
101	        end if;
102	        -- *** decision maker :: states change ***
103	        if init_cmd_i = '1' then
104	          v.fsm_state := zero;
105	        end if;
106	
107	      when flat =>
108	        v.status := "11";
109	        -- *** decision maker :: states change ***
110	        if init_cmd_i = '1' then
111	          v.fsm_state := zero;
112	        elsif ramp_cmd_i = '1' then
113	          if not is_sign_g then
114	            if unsigned(tgt_lvl_i) > r.pulse then
115	              v.fsm_state := up;
116	            else
117	              v.fsm_state := dw;
118	            end if;
119	          else
120	            if signed(tgt_lvl_i) > r.spulse then
121	              v.fsm_state := up;
122	            else
123	              v.fsm_state := dw;
124	            end if;
125	          end if;
126	        end if;
127	
128	      when dw =>
129	        v.status := "10";
130	        -- *** decrease pulse :: accu ***
131	        if vld_i = '1' then
132	          if not is_sign_g then
133	            v.pulse := r.pulse - resize(unsigned(ramp_inc_i), width_g + 1);
134	            if r.pulse(width_g downto 0) <= resize((unsigned(tgt_lvl_i) + unsigned(ramp_inc_i)), width_g + 1) then
135	              v.fsm_state := flat;
136	              v.pulse     := resize(unsigned(tgt_lvl_i), width_g + 1);
137	            end if;
138	          else
139	            --*** is signed ***
140	           v.spulse := r.spulse - resize(signed(ramp_inc_i), width_g + 1);
141	            if r.spulse(width_g downto 0) <= resize((signed(tgt_lvl_i) + signed(ramp_inc_i)), width_g + 1) then
142	              v.fsm_state := flat;
143	              v.spulse    := resize(signed(tgt_lvl_i), width_g + 1);
144	            end if;
145	          end if;
146	        end if;
147	        -- *** decision maker :: states change ***
148	        if init_cmd_i = '1' then
149	          v.fsm_state := zero;
150	        end if;
151	    end case;
152	
153	    --*** clock latency strobe *** 
154	    v.str_s := vld_i;
155	
156	    --*** v to r ***
157	    rin <= v;
158	  end process;
159	
160	  proc_regs : process(clk_i)
161	  begin
162	    if rising_edge(clk_i) then
163	      r <= rin;
164	      --*** sync reset ***
165	      if rst_i = rst_pol_g then
166	        r.fsm_state <= zero;
167	        r.pulse     <= (others => '0');
168	        r.spulse    <= (others => '0');
169	        r.status    <= "00";
170	        r.str_s     <= '0';
171	      end if;
172	    end if;
173	  end process;
174	
175	  --*** out mapping ***--
176	  vld_o  <= r.str_s;
177	  sts_o  <= r.status;
178	  
179	  gen_output_usign : if not is_sign_g generate 
180	  begin
181	   puls_o <= std_logic_vector(r.pulse(width_g - 1 downto 0));
182	  end generate;
183	
184	  gen_output_sign : if is_sign_g generate 
185	  begin
186	   puls_o <= std_logic_vector(r.spulse(width_g - 1 downto 0));
187	 end generate;
188	 
189	end architecture;
