1	------------------------------------------------------------------------------
2	--  Copyright (c) 2020 by Paul Scherrer Institute, Switzerland
3	--  All rights reserved.
4	--  Authors: Benoit Stef
5	------------------------------------------------------------------------------
6	
7	------------------------------------------------------------------------------
8	-- Description
9	------------------------------------------------------------------------------
10	-- This arhitecture is using few elements within the psi common library in order
11	-- to generate a periodic pulse or trigger pulse with predefined parameters
12	-- the architecture target is to show a possible implementaion of 
13	-- psi_common_pulse_generator.vhd
14	-- if trig is set to 1 it will start a pulse from 0 to its max level depending
15	-- on data vector length selected and will return to 0.
16	-- if trig is let to 1 then repetitive pulse will be fired.
17	
18	------------------------------------------------------------------------------
19	-- Libraries
20	------------------------------------------------------------------------------
21	library ieee;
22	use ieee.std_logic_1164.all;
23	use ieee.numeric_std.all;
24	use ieee.math_real.all;
25	
26	use work.psi_common_logic_pkg.all;
27	use work.psi_common_math_pkg.all;
28	use work.psi_common_array_pkg.all;
29	-- @formatter:off
30	entity psi_common_pulse_generator_ctrl_static is
31	  generic(rst_pol_g     : std_logic:= '1';                           -- '1' active high, '0' active low
32	          width_g       : natural  :=      16;                       -- Output data vector length
33	          clk_freq_g    : real     := 100.0e6;                       -- Clock frequency in Hz
34	          str_freq_g    : real     :=  10.0e6;                       -- Strobe output || increment strobe in Hz
35	          nb_step_up_g  : integer  := 100;                           -- ramp up param step in str
36	          nb_step_dw_g  : integer  := 50;                            -- ramp down param step in str
37	          nb_step_flh_g : integer  := 4000;                          -- flat level param step in str
38	          nb_step_fll_g : integer  := 4000);                         -- low level param step in str
39	  port   (clk_i         : in  std_logic;                             -- clock
40	          rst_i         : in  std_logic;                             -- reset
41	          trig_i        : in  std_logic;                             -- Trigger a new pulse
42	          stop_i        : in  std_logic;                             -- Abort pulse
43	          busy_o        : out std_logic;                             -- pulse in action
44	          dat_o         : out std_logic_vector(width_g-1 downto 0);  -- pulse output
45	          vld_o         : out std_logic;                             -- pulse strobe
46	          dbg_o         : out std_logic_vector(1 downto 0));         -- use for tb purpose and avoid using externalname GHDL
47	end entity;
48	-- @formatter:on
49	
50	architecture RTL of psi_common_pulse_generator_ctrl_static is
51	 
52	 signal str_s : std_logic;
53	 signal sts_s : std_logic_vector(1 downto 0);
54	 signal dat_s : std_logic_vector(width_g-1 downto 0);
55	 
56	 -- set of constant for static pulse generation
57	 constant step_array_c  : t_ainteger(1 downto 0):=(nb_step_flh_g,nb_step_fll_g);
58	 constant max_step_c    : integer := max_a(step_array_c);
59	 constant tgt_lvl_c     : std_logic_vector(width_g-1 downto 0) := to_uslv(2**width_g-1,width_g);
60	 constant inc_step_up_c : integer := integer(round(real(from_uslv(tgt_lvl_c))/real(nb_step_up_g)));
61	 constant inc_step_dw_c : integer := integer(round(real(from_uslv(tgt_lvl_c))/real(nb_step_dw_g)));
62	 -- 2 process ctrl
63	 type two_process_t is record
64	  inc_val  : std_logic_vector(width_g-1 downto 0);
65	  ramp_cmd : std_logic;
66	  init_cmd : std_logic;
67	  sts_dff  : std_logic_vector(1 downto 0);
68	  count    : integer range 0 to max_step_c-1;
69	  lvl      : std_logic_vector(width_g-1 downto 0);
70	  trig_dff : std_logic;
71	  busy     : std_logic;
72	 end record;
73	 
74	 signal r, rin : two_process_t;
75	 
76	begin
77	  
78	  --*** Strobe generator ***
79	  inst_strobe : entity work.psi_common_strobe_generator
80	    generic map(
81	      freq_clock_g  => clk_freq_g,
82	      freq_strobe_g => str_freq_g,
83	      rst_pol_g     => rst_pol_g)
84	    port map(
85	      clk_i  => clk_i,
86	      rst_i  => rst_i,
87	      sync_i => trig_i,
88	      vld_o => str_s);
89	  
90	  --*** Pulse generator ***  
91	  inst_pulse : entity work.psi_common_ramp_gene
92	    generic map(
93	      width_g     => width_g,
94	      is_sign_g   => false,
95	      rst_pol_g   => rst_pol_g,
96	      init_val_g  => 0)
97	    port map(
98	      clk_i      => clk_i,
99	      rst_i      => rst_i,
100	      vld_i      => str_s,
101	      tgt_lvl_i  => r.lvl,
102	      ramp_inc_i => r.inc_val,
103	      ramp_cmd_i => r.ramp_cmd,
104	      init_cmd_i => r.init_cmd,
105	      sts_o      => sts_s,
106	      vld_o      => vld_o,
107	      puls_o     => dat_s);
108	  
109	  dbg_o  <= sts_s;  
110	  dat_o  <= dat_s;
111	  busy_o <= r.busy;
112	  
113	  proc_comb : process(sts_s,stop_i,trig_i,r,str_s,dat_s)
114	    variable v : two_process_t;
115	  begin
116	    v:=r;    
117	    -- edge detect
118	    v.trig_dff := trig_i;
119	    v.sts_dff  := sts_s;
120	    -- abort pulse
121	    if stop_i = '1' then
122	      v.init_cmd := '1';
123	      v.count    :=  nb_step_flh_g-1;
124	      v.busy     := '0';
125	    else  
126	      v.init_cmd := '0';
127	      -- wait for trigger
128	      if sts_s = "00" then 
129	        v.busy     := '0';
130	        v.count := nb_step_flh_g-1;
131	        v.lvl   := to_uslv(2**width_g-1,width_g);
132	        if trig_i ='1' and r.trig_dff = '0'  then
133	          v.inc_val  := to_uslv(inc_step_up_c,width_g);
134	          v.ramp_cmd := '1';
135	          v.busy     := '1';
136	        else
137	          v.ramp_cmd := '0';
138	        end if;
139	      -- counter flat top/bottom  
140	    elsif sts_s = "11" then      
141	         if str_s = '1' then
142	           if r.count /= 0 then
143	             v.count := r.count-1;
144	             v.ramp_cmd := '0';
145	             v.busy     := '1';
146	           else
147	             v.count := 0;
148	             if dat_s = to_uslv(0,width_g) then
149	               v.busy     := '0';
150	               if trig_i ='1' then
151	                 v.lvl      := to_uslv(2**width_g-1,width_g);
152	                 v.inc_val  := to_uslv(inc_step_up_c,width_g);
153	                 v.ramp_cmd := '1';
154	                 v.busy     := '1';
155	               end if;
156	             else
157	               v.busy     := '1';
158	               v.lvl      := (others=>'0');  
159	               v.inc_val  := to_uslv(inc_step_dw_c,width_g);
160	               v.ramp_cmd := '1';
161	             end if;
162	           end if;     
163	         end if;
164	      --reset counter start value    
165	      elsif (sts_s = "10" and r.sts_dff = "11") then
166	        v.ramp_cmd := '0';
167	        v.count := nb_step_fll_g-1;
168	      elsif sts_s= "01" and r.sts_dff = "11" then
169	        v.ramp_cmd := '0';
170	        v.count := nb_step_flh_g-1;
171	      end if;
172	     end if;
173	    rin <= v;
174	  end process;
175	  
176	  proc_clk : process(clk_i)
177	  begin
178	    if rising_edge(clk_i) then
179	      if rst_i = rst_pol_g then
180	        r.inc_val  <= (others=>'0');
181	        r.ramp_cmd <= '0';
182	        r.count    <=  nb_step_flh_g-1;
183	        r.lvl      <= (others=>'0');
184	        r.trig_dff <= '0';
185	        r.busy     <= '0';
186	      end if;
187	      r <= rin;
188	    end if;
189	  end process;
190	  
191	end architecture;
192

