7	------------------------------------------------------------------------------
8	-- Description
9	------------------------------------------------------------------------------
10	-- This TB shows a a non conventional way to use the pulse generator within
11	-- the PSI COMMON, the target level is always moidified and it doesn't produce 
12	-- pulse but allow the user to ramp up/down to a desired value, datagram can
13	-- be observed here below  
14	--                                                   ________
15	--                 _______                          /  
16	--                /       \       _____            /
17	--               /         \_____/     \          /
18	--        ______/                       \        /
19	-- ______/                               \______/
20	
21	------------------------------------------------------------------------------
22	-- Libraries
23	------------------------------------------------------------------------------
24	library ieee;
25	use ieee.std_logic_1164.all;
26	use ieee.numeric_std.all;
27	use ieee.math_real.all;
28	
29	use work.psi_tb_activity_pkg.all;
30	use work.psi_tb_txt_util.all;
31	use work.psi_common_math_pkg.all;
32	
33	entity psi_common_ramp_gene_tb is
34	  generic(freq_clk_g : real    := 100.0E6;
35	          width_g    : natural := 16
36	         );
37	end entity;
38	
39	architecture tb of psi_common_ramp_gene_tb is
40	
41	  constant period_c             : time                                   := (1 sec) / freq_clk_g;
42	  signal clk_i                  : std_logic                              := '0';
43	  signal tb_run                 : boolean                                := true;
44	  --------------------------------------------------------------------
45	  signal rst_i                  : std_logic                              := '1';
46	  signal InStr                  : std_logic                              := '0';
47	  signal RampInc                : std_logic_vector(width_g - 1 downto 0) := (std_logic_vector(to_unsigned(100, width_g)));
48	  signal RampCmd                : std_logic                              := '0';
49	  signal InInitCmd              : std_logic                              := '0';
50	  -------------------------------------------------------------------
51	  signal OutSts                 : std_logic_vector(1 downto 0);
52	  signal OutStr                 : std_logic;
53	  signal OutPuls, OutPuls_dff   : std_logic_vector(width_g - 1 downto 0);
54	  signal TgtLevel               : std_logic_vector(width_g - 1 downto 0) := (std_logic_vector(to_unsigned(2000, width_g)));
55	  -------------------------------------------------------------------
56	  signal TgtLevel2              : std_logic_vector(width_g - 1 downto 0) := to_sslv(2000, width_g);
57	  signal sOutSts                : std_logic_vector(1 downto 0);
58	  signal sOutStr                : std_logic;
59	  signal sOutPuls, sOutPuls_dff : std_logic_vector(width_g - 1 downto 0);
60	
61	begin
62	  --*** automatic check process ***
63	  process(clk_i)
64	  begin
65	    if falling_edge(clk_i) then
66	      OutPuls_dff <= OutPuls;
