141	  end process;
142	
143	  --*** DUT ***
144	  i_dut : entity work.psi_common_ramp_gene
145	    generic map(width_g   => width_g,
146	                rst_pol_g => '1')
147	    port map(
148	      clk_i      => clk_i,
